import{_ as o,o as l,c,ai as i}from"./chunks/framework.CsYGeNYI.js";const m=JSON.parse('{"title":"发布清单（npm + macOS）","description":"","frontmatter":{"read_when":["发布新的 npm 版本","发布新的 macOS 应用版本","发布前验证元数据"],"summary":"npm + macOS 应用的逐步发布清单","x-i18n":{"generated_at":"2026-02-03T10:09:28Z","model":"claude-opus-4-5","provider":"pi","source_hash":"1a684bc26665966eb3c9c816d58d18eead008fd710041181ece38c21c5ff1c62","source_path":"reference/RELEASING.md","workflow":15}},"headers":[],"relativePath":"zh-CN/reference/RELEASING.md","filePath":"zh-CN/reference/RELEASING.md","lastUpdated":1771906665000}'),s={name:"zh-CN/reference/RELEASING.md"};function d(n,e,t,a,p,r){return l(),c("div",null,[...e[0]||(e[0]=[i('<h1 id="发布清单-npm-macos" tabindex="-1"><a class="header-anchor" href="#发布清单-npm-macos">#</a> 发布清单（npm + macOS）</h1><p>从仓库根目录使用 <code>pnpm</code>（Node 22+）。在打标签/发布前保持工作树干净。</p><h2 id="操作员触发" tabindex="-1"><a class="header-anchor" href="#操作员触发">#</a> 操作员触发</h2><p>当操作员说&quot;release&quot;时，立即执行此预检（除非遇到阻碍否则不要额外提问）：</p><ul><li>阅读本文档和 <code>docs/platforms/mac/release.md</code>。</li><li>从 <code>~/.profile</code> 加载环境变量并确认 <code>SPARKLE_PRIVATE_KEY_FILE</code> + App Store Connect 变量已设置（SPARKLE_PRIVATE_KEY_FILE 应位于 <code>~/.profile</code> 中）。</li><li>如需要，使用 <code>~/Library/CloudStorage/Dropbox/Backup/Sparkle</code> 中的 Sparkle 密钥。</li></ul><ol><li><strong>版本和元数据</strong></li></ol><ul><li>[ ] 更新 <code>package.json</code> 版本（例如 <code>2026.1.29</code>）。</li><li>[ ] 运行 <code>pnpm plugins:sync</code> 以对齐扩展包版本和变更日志。</li><li>[ ] 更新 CLI/版本字符串：<a href="https://github.com/NJX-njx/opensoul/blob/main/src/cli/program.ts" target="_blank" rel="noreferrer"><code>src/cli/program.ts</code></a> 和 <a href="https://github.com/NJX-njx/opensoul/blob/main/src/provider-web.ts" target="_blank" rel="noreferrer"><code>src/provider-web.ts</code></a> 中的 Baileys user agent。</li><li>[ ] 确认包元数据（name、description、repository、keywords、license）以及 <code>bin</code> 映射指向 <a href="https://github.com/NJX-njx/opensoul/blob/main/opensoul.mjs" target="_blank" rel="noreferrer"><code>opensoul.mjs</code></a> 作为 <code>opensoul</code>。</li><li>[ ] 如果依赖项有变化，运行 <code>pnpm install</code> 确保 <code>pnpm-lock.yaml</code> 是最新的。</li></ul><ol start="2"><li><strong>构建和产物</strong></li></ol><ul><li>[ ] 如果 A2UI 输入有变化，运行 <code>pnpm canvas:a2ui:bundle</code> 并提交更新后的 <a href="https://github.com/NJX-njx/opensoul/blob/main/src/canvas-host/a2ui/a2ui.bundle.js" target="_blank" rel="noreferrer"><code>src/canvas-host/a2ui/a2ui.bundle.js</code></a>。</li><li>[ ] <code>pnpm run build</code>（重新生成 <code>dist/</code>）。</li><li>[ ] 验证 npm 包的 <code>files</code> 包含所有必需的 <code>dist/*</code> 文件夹（特别是用于 headless node + ACP CLI 的 <code>dist/node-host/**</code> 和 <code>dist/acp/**</code>）。</li><li>[ ] 确认 <code>dist/build-info.json</code> 存在并包含预期的 <code>commit</code> 哈希（CLI 横幅在 npm 安装时使用此信息）。</li><li>[ ] 可选：构建后运行 <code>npm pack --pack-destination /tmp</code>；检查 tarball 内容并保留以备 GitHub 发布使用（<strong>不要</strong>提交它）。</li></ul><ol start="3"><li><strong>变更日志和文档</strong></li></ol><ul><li>[ ] 更新 <code>CHANGELOG.md</code>，添加面向用户的亮点（如果文件不存在则创建）；按版本严格降序排列条目。</li><li>[ ] 确保 README 示例/标志与当前 CLI 行为匹配（特别是新命令或选项）。</li></ul><ol start="4"><li><strong>验证</strong></li></ol><ul><li>[ ] <code>pnpm build</code></li><li>[ ] <code>pnpm check</code></li><li>[ ] <code>pnpm test</code>（如需覆盖率输出则使用 <code>pnpm test:coverage</code>）</li><li>[ ] <code>pnpm release:check</code>（验证 npm pack 内容）</li><li>[ ] <code>OPENSOUL_INSTALL_SMOKE_SKIP_NONROOT=1 pnpm test:install:smoke</code>（Docker 安装冒烟测试，快速路径；发布前必需） <ul><li>如果已知上一个 npm 发布版本有问题，为预安装步骤设置 <code>OPENSOUL_INSTALL_SMOKE_PREVIOUS=&lt;last-good-version&gt;</code> 或 <code>OPENSOUL_INSTALL_SMOKE_SKIP_PREVIOUS=1</code>。</li></ul></li><li>[ ]（可选）完整安装程序冒烟测试（添加非 root + CLI 覆盖）：<code>pnpm test:install:smoke</code></li><li>[ ]（可选）安装程序 E2E（Docker，运行 <code>curl -fsSL https://opensoul.ai/install.sh | bash</code>，新手引导，然后运行真实工具调用）： <ul><li><code>pnpm test:install:e2e:openai</code>（需要 <code>OPENAI_API_KEY</code>）</li><li><code>pnpm test:install:e2e:anthropic</code>（需要 <code>ANTHROPIC_API_KEY</code>）</li><li><code>pnpm test:install:e2e</code>（需要两个密钥；运行两个提供商）</li></ul></li><li>[ ]（可选）如果你的更改影响发送/接收路径，抽查 Web Gateway 网关。</li></ul><ol start="5"><li><strong>macOS 应用（Sparkle）</strong></li></ol><ul><li>[ ] 构建并签名 macOS 应用，然后压缩以供分发。</li><li>[ ] 生成 Sparkle appcast（通过 <a href="https://github.com/NJX-njx/opensoul/blob/main/scripts/make_appcast.sh" target="_blank" rel="noreferrer"><code>scripts/make_appcast.sh</code></a> 生成 HTML 注释）并更新 <code>appcast.xml</code>。</li><li>[ ] 保留应用 zip（和可选的 dSYM zip）以便附加到 GitHub 发布。</li><li>[ ] 按照 <a href="/docs/platforms/mac/release">macOS 发布</a> 获取确切命令和所需环境变量。 <ul><li><code>APP_BUILD</code> 必须是数字且单调递增（不带 <code>-beta</code>），以便 Sparkle 正确比较版本。</li><li>如果进行公证，使用从 App Store Connect API 环境变量创建的 <code>opensoul-notary</code> 钥匙串配置文件（参见 <a href="/docs/platforms/mac/release">macOS 发布</a>）。</li></ul></li></ul><ol start="6"><li><strong>发布（npm）</strong></li></ol><ul><li>[ ] 确认 git 状态干净；根据需要提交并推送。</li><li>[ ] 如需要，<code>npm login</code>（验证 2FA）。</li><li>[ ] <code>npm publish --access public</code>（预发布版本使用 <code>--tag beta</code>）。</li><li>[ ] 验证注册表：<code>npm view opensoul version</code>、<code>npm view opensoul dist-tags</code> 和 <code>npx -y opensoul@X.Y.Z --version</code>（或 <code>--help</code>）。</li></ul><h3 id="故障排除-来自-2-0-0-beta2-发布的笔记" tabindex="-1"><a class="header-anchor" href="#故障排除-来自-2-0-0-beta2-发布的笔记">#</a> 故障排除（来自 2.0.0-beta2 发布的笔记）</h3><ul><li><strong>npm pack/publish 挂起或产生巨大 tarball</strong>：<code>dist/OpenSoul.app</code> 中的 macOS 应用包（和发布 zip）被扫入包中。通过 <code>package.json</code> 的 <code>files</code> 白名单发布内容来修复（包含 dist 子目录、docs、skills；排除应用包）。用 <code>npm pack --dry-run</code> 确认 <code>dist/OpenSoul.app</code> 未列出。</li><li><strong>npm auth dist-tags 的 Web 循环</strong>：使用旧版认证以获取 OTP 提示： <ul><li><code>NPM_CONFIG_AUTH_TYPE=legacy npm dist-tag add opensoul@X.Y.Z latest</code></li></ul></li><li><strong><code>npx</code> 验证失败并显示 <code>ECOMPROMISED: Lock compromised</code></strong>：使用新缓存重试： <ul><li><code>NPM_CONFIG_CACHE=/tmp/npm-cache-$(date +%s) npx -y opensoul@X.Y.Z --version</code></li></ul></li><li><strong>延迟修复后需要重新指向标签</strong>：强制更新并推送标签，然后确保 GitHub 发布资产仍然匹配： <ul><li><code>git tag -f vX.Y.Z &amp;&amp; git push -f origin vX.Y.Z</code></li></ul></li></ul><ol start="7"><li><strong>GitHub 发布 + appcast</strong></li></ol><ul><li>[ ] 打标签并推送：<code>git tag vX.Y.Z &amp;&amp; git push origin vX.Y.Z</code>（或 <code>git push --tags</code>）。</li><li>[ ] 为 <code>vX.Y.Z</code> 创建/刷新 GitHub 发布，<strong>标题为 <code>opensoul X.Y.Z</code></strong>（不仅仅是标签）；正文应包含该版本的<strong>完整</strong>变更日志部分（亮点 + 更改 + 修复），内联显示（无裸链接），且<strong>不得在正文中重复标题</strong>。</li><li>[ ] 附加产物：<code>npm pack</code> tarball（可选）、<code>OpenSoul-X.Y.Z.zip</code> 和 <code>OpenSoul-X.Y.Z.dSYM.zip</code>（如果生成）。</li><li>[ ] 提交更新后的 <code>appcast.xml</code> 并推送（Sparkle 从 main 获取源）。</li><li>[ ] 从干净的临时目录（无 <code>package.json</code>），运行 <code>npx -y opensoul@X.Y.Z send --help</code> 确认安装/CLI 入口点正常工作。</li><li>[ ] 宣布/分享发布说明。</li></ul><h2 id="插件发布范围-npm" tabindex="-1"><a class="header-anchor" href="#插件发布范围-npm">#</a> 插件发布范围（npm）</h2><p>我们只发布 <code>@opensoul/*</code> 范围下的<strong>现有 npm 插件</strong>。不在 npm 上的内置插件保持<strong>仅磁盘树</strong>（仍在 <code>extensions/**</code> 中发布）。</p><p>获取列表的流程：</p><ol><li><code>npm search @opensoul --json</code> 并捕获包名。</li><li>与 <code>extensions/*/package.json</code> 名称比较。</li><li>只发布<strong>交集</strong>（已在 npm 上）。</li></ol><p>当前 npm 插件列表（根据需要更新）：</p><ul><li>@opensoul/bluebubbles</li><li>@opensoul/diagnostics-otel</li><li>@opensoul/discord</li><li>@opensoul/lobster</li><li>@opensoul/matrix</li><li>@opensoul/msteams</li><li>@opensoul/nextcloud-talk</li><li>@opensoul/nostr</li><li>@opensoul/voice-call</li><li>@opensoul/zalo</li><li>@opensoul/zalouser</li></ul><p>发布说明还必须标注<strong>默认未启用</strong>的<strong>新可选内置插件</strong>（例如：<code>tlon</code>）。</p>',28)])])}const g=o(s,[["render",d]]);export{m as __pageData,g as default};
